import{_ as o,o as r,c as a,ag as t}from"./chunks/framework.BZohXCq9.js";const l=JSON.parse('{"title":"附录 C　名词解释（Glossary）","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/appendix-c-glossary.md","filePath":"chapters/appendix-c-glossary.md"}'),d={name:"chapters/appendix-c-glossary.md"};function n(s,e,c,i,p,g){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="附录-c-名词解释-glossary" tabindex="-1">附录 C　名词解释（Glossary） <a class="header-anchor" href="#附录-c-名词解释-glossary" aria-label="Permalink to &quot;附录 C　名词解释（Glossary）&quot;">​</a></h1><h2 id="a" tabindex="-1">A <a class="header-anchor" href="#a" aria-label="Permalink to &quot;A&quot;">​</a></h2><p><strong>actor_id</strong> 在多参与方场景（如群聊、多 Agent）中，标识具体发言者的 ID。与 <code>user_id</code> 的区别：<code>user_id</code> 标识记忆所属的用户，<code>actor_id</code> 标识某条消息的说话人。</p><p><strong>add()</strong> mem0 的核心写入方法。内部触发两次 LLM 调用（事实提取 + 更新决策），再并行写入向量库和图数据库。</p><p><strong>agent_id</strong> 标识 AI Agent 的 ID，用于存储 Agent 自身的程序性知识（工作方法、操作策略等）。与 <code>user_id</code> 正交，可组合使用。</p><p><strong>AsyncMemory / AsyncMemoryClient</strong><code>Memory</code> 和 <code>MemoryClient</code> 的异步版本，内部使用 <code>asyncio</code>，适合 FastAPI 等异步框架。</p><h2 id="b" tabindex="-1">B <a class="header-anchor" href="#b" aria-label="Permalink to &quot;B&quot;">​</a></h2><p><strong>BM25（Best Match 25）</strong> 一种基于词频-逆文档频率的文本检索算法。在 mem0 的图记忆搜索中，用于对向量搜索的结果做二次重排序。</p><p><strong>base_label</strong> 图存储配置项。当为 <code>True</code> 时，所有节点统一打上 <code>__Entity__</code> 标签，方便批量操作和索引管理。</p><h2 id="c" tabindex="-1">C <a class="header-anchor" href="#c" aria-label="Permalink to &quot;C&quot;">​</a></h2><p><strong>collection_name</strong> 向量库中集合（相当于表）的名称，默认为 <code>&quot;mem0&quot;</code>。同一个向量库实例可以有多个集合，用于隔离不同应用的记忆。</p><p><strong>Cross-Encoder</strong> Reranker 使用的模型架构，对查询和文档做联合建模，精度高于 Bi-Encoder（向量搜索），但速度慢。</p><p><strong>custom_fact_extraction_prompt</strong> 覆盖默认 <code>FACT_RETRIEVAL_PROMPT</code> 的自定义 Prompt，用于领域特化的事实提取逻辑。</p><p><strong>custom_update_memory_prompt</strong> 覆盖默认 <code>DEFAULT_UPDATE_MEMORY_PROMPT</code> 的自定义 Prompt，用于自定义记忆更新/冲突解消规则。</p><p><strong>Cypher</strong> Neo4j 图数据库的查询语言，类似 SQL。mem0 用 Cypher 进行图节点的 MERGE、MATCH、DELETE 操作。</p><h2 id="d" tabindex="-1">D <a class="header-anchor" href="#d" aria-label="Permalink to &quot;D&quot;">​</a></h2><p><strong>DEFAULT_UPDATE_MEMORY_PROMPT</strong> 控制记忆更新决策的核心 Prompt，指导 LLM 在 ADD/UPDATE/DELETE/NONE 四种操作中做出选择。</p><h2 id="e" tabindex="-1">E <a class="header-anchor" href="#e" aria-label="Permalink to &quot;E&quot;">​</a></h2><p><strong>EmbeddingBase</strong> 所有 Embedder 适配器的抽象基类，只有一个方法：<code>embed(text, memory_action)</code>。</p><p><strong>EmbedderFactory</strong> 动态创建 Embedder 实例的工厂类，通过 provider 字符串（如 <code>&quot;openai&quot;</code>）懒加载对应的实现类。</p><p><strong>embedding_model_dims</strong> 向量的维度数，必须与向量库中集合的配置一致。常见值：384（轻量模型）、768、1024、1536（OpenAI 小模型）、3072（OpenAI 大模型）。</p><p><strong>event</strong><code>add()</code> 返回结果中每条记忆操作的类型，有四种：<code>ADD</code>（新增）、<code>UPDATE</code>（更新）、<code>DELETE</code>（删除）、<code>NONE</code>（无变化）。</p><h2 id="f" tabindex="-1">F <a class="header-anchor" href="#f" aria-label="Permalink to &quot;F&quot;">​</a></h2><p><strong>FACT_RETRIEVAL_PROMPT</strong> mem0 的事实提取 Prompt，指导 LLM 从对话中提取有价值的个人信息事实，并以 JSON 格式返回。</p><p><strong>FastEmbed</strong> Qdrant 团队开发的高性能本地 Embedding 推理库，使用 ONNX Runtime，比 PyTorch 快 2-4x。</p><p><strong>filters</strong><code>search()</code> 和 <code>get_all()</code> 中的过滤参数，支持简单精确匹配和高级运算符（<code>eq/ne/gt/gte/lt/lte/in/nin/contains/AND/OR/NOT</code>）。</p><h2 id="g" tabindex="-1">G <a class="header-anchor" href="#g" aria-label="Permalink to &quot;G&quot;">​</a></h2><p><strong>GraphStoreFactory</strong> 创建图存储实例的工厂类，当前主要支持 Neo4j。</p><p><strong>graph_memory</strong> 向量记忆的补充，以实体关系三元组（source-relationship-target）的形式存储知识，支持多跳推理。</p><h2 id="h" tabindex="-1">H <a class="header-anchor" href="#h" aria-label="Permalink to &quot;H&quot;">​</a></h2><p><strong>hash</strong> 记忆文本的 MD5 hash，存储在向量库的 payload 中，用于快速去重检测。</p><p><strong>history.db</strong> SQLite 数据库文件（默认路径 <code>~/.mem0/history.db</code>），存储每条记忆的完整变更历史（ADD/UPDATE/DELETE 事件）。</p><p><strong>HNSW（Hierarchical Navigable Small World）</strong> 向量近似最近邻（ANN）搜索的索引算法，在 pgvector 和 Qdrant 中可选启用，平衡检索速度和精度。</p><h2 id="i" tabindex="-1">I <a class="header-anchor" href="#i" aria-label="Permalink to &quot;I&quot;">​</a></h2><p><strong>infer</strong><code>add()</code> 的参数，默认 <code>True</code>（LLM 智能提取事实）。设为 <code>False</code> 时跳过 LLM，直接原始存储消息文本。</p><h2 id="l" tabindex="-1">L <a class="header-anchor" href="#l" aria-label="Permalink to &quot;L&quot;">​</a></h2><p><strong>LangGraph</strong> 基于 Pregel 计算模型的 AI Agent 状态机框架，可与 mem0 集成实现带记忆的状态图。</p><p><strong>LLMBase</strong> 所有 LLM 适配器的抽象基类，核心方法：<code>generate_response(messages, tools, tool_choice)</code>。</p><p><strong>LlmFactory</strong> 动态创建 LLM 实例的工厂类，支持 15+ 提供商。</p><h2 id="m" tabindex="-1">M <a class="header-anchor" href="#m" aria-label="Permalink to &quot;M&quot;">​</a></h2><p><strong>Matryoshka embeddings</strong> OpenAI text-embedding-3 系列支持的维度缩减技术，可以用更小的维度（如 512）获得合理精度，降低存储和计算成本。</p><p><strong>MemoryBase</strong><code>Memory</code> 和 <code>MemoryClient</code> 共同继承的抽象基类，定义了 7 个接口方法（add/search/get/get_all/update/delete/history）。</p><p><strong>MemoryClient</strong> 连接 mem0 托管平台的客户端，通过 HTTP API 调用云端记忆服务，无需本地组件。</p><p><strong>MemoryConfig</strong> mem0 的根配置模型（Pydantic BaseModel），包含 LLM、Embedder、向量库、图存储等所有子配置。</p><p><strong>MemoryGraph</strong> mem0 的图记忆实现类，基于 Neo4j，负责实体提取、关系构建和图搜索。</p><p><strong>MemoryItem</strong> 单条记忆的数据结构（Pydantic 模型），包含 id/memory/hash/metadata/score/created_at/updated_at。</p><p><strong>memory_type</strong><code>add()</code> 的可选参数，当前仅支持 <code>&quot;procedural_memory&quot;</code>（程序性记忆），用于 Agent 存储工作方法。</p><h2 id="n" tabindex="-1">N <a class="header-anchor" href="#n" aria-label="Permalink to &quot;N&quot;">​</a></h2><p><strong>NONE event</strong> 在 <code>add()</code> 的更新决策中，当新事实与已有记忆语义相同时，LLM 返回 NONE 操作。v1.0 新增：即使内容不变，也会更新 session ID。</p><h2 id="o" tabindex="-1">O <a class="header-anchor" href="#o" aria-label="Permalink to &quot;O&quot;">​</a></h2><p><strong>on_disk</strong> Qdrant 配置项，<code>True</code> 时开启磁盘持久化，<code>False</code>（默认）时纯内存模式（重启后数据丢失）。</p><p><strong>OpenMemory</strong> mem0 官方出品的本地 MCP Server，把 mem0 的记忆能力通过 MCP 协议分享给 Claude Desktop、Cursor 等工具。</p><h2 id="p" tabindex="-1">P <a class="header-anchor" href="#p" aria-label="Permalink to &quot;P&quot;">​</a></h2><p><strong>payload</strong> 向量库中与向量一起存储的元数据字典，包含记忆文本（<code>data</code>）、hash、user_id、created_at 等字段。</p><p><strong>procedural_memory</strong> 程序性记忆，记录 Agent 的工作方法和操作策略，而非用户偏好。通过 <code>memory_type=&quot;procedural_memory&quot;</code> 触发专用提取 Prompt。</p><h2 id="r" tabindex="-1">R <a class="header-anchor" href="#r" aria-label="Permalink to &quot;R&quot;">​</a></h2><p><strong>Reranker</strong> 在向量搜索之后、结果返回之前，用交叉编码器对候选记忆重新排序，提升检索精度。可选组件。</p><p><strong>run_id</strong> 标识单次对话会话的 ID，存储单次对话中的临时记忆，与 <code>user_id</code>、<code>agent_id</code> 正交，可组合。</p><h2 id="s" tabindex="-1">S <a class="header-anchor" href="#s" aria-label="Permalink to &quot;S&quot;">​</a></h2><p><strong>sanitize_relationship_for_cypher()</strong> 对 LLM 生成的关系名做清理，移除非法字符，转为大写下划线格式（如 <code>&quot;lives in&quot;</code> → <code>&quot;LIVES_IN&quot;</code>），确保 Cypher 安全。</p><p><strong>score</strong><code>search()</code> 返回的相似度分数（0-1），越高表示与查询越相关。</p><p><strong>SQLiteManager</strong> 管理 <code>history.db</code> 的类，提供 <code>add_history()</code> 和 <code>get_history()</code> 方法，支持线程安全和 Schema 迁移。</p><h2 id="t" tabindex="-1">T <a class="header-anchor" href="#t" aria-label="Permalink to &quot;T&quot;">​</a></h2><p><strong>temp_uuid_mapping</strong><code>add()</code> 内部用于 LLM 交互的整数 ID 映射表。把 UUID 替换为简单整数传给 LLM，避免 UUID 幻觉，用完再还原。</p><p><strong>threshold</strong><code>search()</code> 的相似度过滤阈值，只返回分数 ≥ threshold 的结果。未设置时返回全部。</p><p><strong>Tool Calling / Function Calling</strong> LLM 的工具调用能力，在 mem0 的图记忆中用于实体提取、关系建立和冲突解消。</p><h2 id="u" tabindex="-1">U <a class="header-anchor" href="#u" aria-label="Permalink to &quot;U&quot;">​</a></h2><p><strong>UPDATE_GRAPH_PROMPT</strong> 图记忆中用于冲突解消的 Prompt，指导 LLM 对比新旧图记忆，决定哪些关系需要更新。</p><p><strong>user_id</strong> 标识记忆所属用户的 ID，是最常用的记忆范围参数。必须与 <code>agent_id</code>/<code>run_id</code> 三者至少提供一个。</p><h2 id="v" tabindex="-1">V <a class="header-anchor" href="#v" aria-label="Permalink to &quot;V&quot;">​</a></h2><p><strong>VectorStoreBase</strong> 所有向量库适配器的抽象基类，定义 11 个方法（insert/search/delete/update/get/list/reset 等）。</p><p><strong>VectorStoreFactory</strong> 动态创建向量库实例的工厂类，支持 20+ 提供商，通过懒加载避免未安装的 SDK 导致 import 错误。</p><h2 id="w" tabindex="-1">W <a class="header-anchor" href="#w" aria-label="Permalink to &quot;W&quot;">​</a></h2><p><strong>WAL（Write-Ahead Logging）</strong> SQLite 的高性能写入模式，mem0 默认未启用，因为历史记录的写入频率通常不高。</p>',74)])])}const m=o(d,[["render",n]]);export{l as __pageData,m as default};
